"""
Topic 8: Thermodynamics - Practice Exercises
First/Second Law, thermodynamic processes, cycles, efficiency

These exercises test understanding of thermodynamic principles and applications.
"""

import numpy as np
from scipy.integrate import trapz

# Physical constants\nR = 8.314  # Gas constant (J/(mol*K))\nk_B = 1.381e-23  # Boltzmann constant (J/K)\n\n# ============================================================================\n# Exercise 1: First Law - Internal Energy Change\n# ============================================================================\n\ndef exercise_1():\n    \"\"\"\n    A system absorbs Q = 500 J of heat and work W = 200 J is done by the system.\n    Calculate the change in internal energy.\n    \n    First Law: ΔU = Q - W\n    \"\"\"\n    Q = 500  # J (heat absorbed)\n    W = 200  # J (work done by system)\n    \n    delta_U = Q - W\n    \n    print(\"Exercise 1: First Law of Thermodynamics\")\n    print(f\"  Heat absorbed: Q = {Q} J\")\n    print(f\"  Work done by system: W = {W} J\")\n    print(f\"  Internal energy change: ΔU = Q - W = {delta_U} J\")\n    print(f\"  Interpretation: System's internal energy increases by {delta_U} J\")\n    print()\n    return delta_U\n\n\n# ============================================================================\n# Exercise 2: Isothermal Process of Ideal Gas\n# ============================================================================\n\ndef exercise_2():\n    \"\"\"\n    An ideal gas undergoes isothermal expansion:\n    - n = 2 moles\n    - T = 300 K (constant)\n    - V_i = 0.01 m³, V_f = 0.05 m³\n    \n    Calculate heat absorbed, work done, and verify ΔU = 0.\n    \"\"\"\n    n = 2  # moles\n    T = 300  # K (constant)\n    V_i = 0.01  # m³\n    V_f = 0.05  # m³\n    \n    # For isothermal process: W = nRT ln(Vf/Vi)\n    W = n * R * T * np.log(V_f / V_i)\n    \n    # For ideal gas at constant T: ΔU = 0\n    delta_U = 0\n    \n    # From First Law: Q = ΔU + W\n    Q = delta_U + W\n    \n    print(\"Exercise 2: Isothermal Process\")\n    print(f\"  Number of moles: n = {n} mol\")\n    print(f\"  Temperature: T = {T} K (constant)\")\n    print(f\"  Initial volume: V_i = {V_i} m³\")\n    print(f\"  Final volume: V_f = {V_f} m³\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Work done by gas: W = nRT ln(Vf/Vi) = {W:.1f} J\")\n    print(f\"  Internal energy change: ΔU = 0 J (temperature constant)\")\n    print(f\"  Heat absorbed: Q = ΔU + W = {Q:.1f} J\")\n    print()\n    return Q, W\n\n\n# ============================================================================\n# Exercise 3: Adiabatic Process\n# ============================================================================\n\ndef exercise_3():\n    \"\"\"\n    An ideal gas undergoes adiabatic expansion:\n    - n = 1 mole\n    - γ = 1.4 (diatomic)\n    - T_i = 400 K, T_f = 300 K\n    \n    Calculate work done and verify Q = 0.\n    \"\"\"\n    n = 1  # mole\n    gamma = 1.4\n    T_i = 400  # K\n    T_f = 300  # K\n    C_V = (5/2) * R  # For diatomic gas\n    \n    # For adiabatic process: W = nCv(Ti - Tf) / (γ - 1)\n    # But simpler: W = nR(Ti - Tf) / (γ - 1)\n    W = n * R * (T_i - T_f) / (gamma - 1)\n    \n    # For adiabatic: Q = 0\n    Q = 0\n    \n    # From First Law: ΔU = Q - W = -W\n    delta_U = -W\n    \n    # Check using ΔU = nCv ΔT\n    delta_U_check = n * C_V * (T_f - T_i)\n    \n    print(\"Exercise 3: Adiabatic Process\")\n    print(f\"  Number of moles: n = {n} mol\")\n    print(f\"  Heat capacity ratio: γ = {gamma}\")\n    print(f\"  Initial temperature: T_i = {T_i} K\")\n    print(f\"  Final temperature: T_f = {T_f} K\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Heat transfer: Q = 0 J (adiabatic)\")\n    print(f\"  Work done by gas: W = nR(Ti-Tf)/(γ-1) = {W:.1f} J\")\n    print(f\"  Internal energy change: ΔU = -W = {delta_U:.1f} J\")\n    print(f\"  Check: ΔU = nCv(Tf-Ti) = {delta_U_check:.1f} J (matches!)\")\n    print()\n    return Q, W, delta_U\n\n\n# ============================================================================\n# Exercise 4: Isobaric Process\n# ============================================================================\n\ndef exercise_4():\n    \"\"\"\n    An ideal gas at constant pressure:\n    - n = 1 mole\n    - P = 101,325 Pa (1 atm)\n    - T_i = 300 K, T_f = 400 K\n    \n    Calculate work, heat absorbed, and ΔU.\n    \"\"\"\n    n = 1  # mole\n    P = 101325  # Pa (1 atm)\n    T_i = 300  # K\n    T_f = 400  # K\n    C_V = (5/2) * R  # For diatomic gas\n    C_p = (7/2) * R  # For diatomic gas\n    \n    # From ideal gas law at constant P: PΔV = nRΔT\n    delta_V = n * R * (T_f - T_i) / P\n    \n    # Work at constant pressure: W = PΔV\n    W = P * delta_V\n    \n    # Heat at constant pressure: Q = nCp ΔT\n    Q = n * C_p * (T_f - T_i)\n    \n    # Internal energy: ΔU = nCv ΔT\n    delta_U = n * C_V * (T_f - T_i)\n    \n    # Check First Law: Q = ΔU + W\n    Q_check = delta_U + W\n    \n    print(\"Exercise 4: Isobaric Process (Constant Pressure)\")\n    print(f\"  Number of moles: n = {n} mol\")\n    print(f\"  Pressure: P = {P} Pa = {P/101325:.2f} atm\")\n    print(f\"  Initial temperature: T_i = {T_i} K\")\n    print(f\"  Final temperature: T_f = {T_f} K\")\n    print(f\"  Temperature change: ΔT = {T_f - T_i} K\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Volume change: ΔV = nR·ΔT/P = {delta_V:.6f} m³\")\n    print(f\"  Work done by gas: W = P·ΔV = {W:.1f} J\")\n    print(f\"  Heat absorbed: Q = nCp·ΔT = {Q:.1f} J\")\n    print(f\"  Internal energy change: ΔU = nCv·ΔT = {delta_U:.1f} J\")\n    print(f\"  Check First Law: Q = ΔU + W? {Q:.1f} = {Q_check:.1f}? {np.isclose(Q, Q_check)}\")\n    print()\n    return Q, W, delta_U\n\n\n# ============================================================================\n# Exercise 5: Isochoric Process\n# ============================================================================\n\ndef exercise_5():\n    \"\"\"\n    An ideal gas at constant volume:\n    - n = 1 mole\n    - V = 0.025 m³ (constant)\n    - T_i = 300 K, T_f = 600 K\n    \n    Calculate pressure change, heat, work, and ΔU.\n    \"\"\"\n    n = 1  # mole\n    V = 0.025  # m³ (constant)\n    T_i = 300  # K\n    T_f = 600  # K\n    C_V = (5/2) * R  # For diatomic gas\n    \n    # Work at constant volume: W = 0\n    W = 0\n    \n    # Heat at constant volume: Q = nCv ΔT\n    Q = n * C_V * (T_f - T_i)\n    \n    # Internal energy: ΔU = nCv ΔT\n    delta_U = n * C_V * (T_f - T_i)\n    \n    # Pressure from ideal gas law\n    P_i = n * R * T_i / V\n    P_f = n * R * T_f / V\n    \n    print(\"Exercise 5: Isochoric Process (Constant Volume)\")\n    print(f\"  Number of moles: n = {n} mol\")\n    print(f\"  Volume: V = {V} m³ (constant)\")\n    print(f\"  Initial temperature: T_i = {T_i} K\")\n    print(f\"  Final temperature: T_f = {T_f} K\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Initial pressure: P_i = {P_i:.0f} Pa\")\n    print(f\"  Final pressure: P_f = {P_f:.0f} Pa\")\n    print(f\"  Work done: W = 0 J (volume constant)\")\n    print(f\"  Heat absorbed: Q = nCv·ΔT = {Q:.1f} J\")\n    print(f\"  Internal energy change: ΔU = {delta_U:.1f} J\")\n    print(f\"  Verify First Law: Q = ΔU + W? {Q:.1f} = {delta_U:.1f}\")\n    print()\n    return Q, W, delta_U\n\n\n# ============================================================================\n# Exercise 6: Carnot Efficiency\n# ============================================================================\n\ndef exercise_6():\n    \"\"\"\n    A Carnot engine operates between:\n    - T_H = 600 K (hot reservoir)\n    - T_C = 300 K (cold reservoir)\n    - Q_H = 5000 J (heat absorbed)\n    \n    Calculate efficiency, work output, and heat rejected.\n    \"\"\"\n    T_H = 600  # K\n    T_C = 300  # K\n    Q_H = 5000  # J\n    \n    # Carnot efficiency\n    eta_carnot = 1 - T_C / T_H\n    \n    # Work output: W = η × Q_H\n    W = eta_carnot * Q_H\n    \n    # Heat rejected: Q_C = Q_H - W\n    Q_C = Q_H - W\n    \n    # Check: Q_C / T_C = Q_H / T_H for Carnot cycle\n    ratio_check = Q_C / T_C - Q_H / T_H\n    \n    print(\"Exercise 6: Carnot Engine Efficiency\")\n    print(f\"  Hot reservoir: T_H = {T_H} K\")\n    print(f\"  Cold reservoir: T_C = {T_C} K\")\n    print(f\"  Heat absorbed: Q_H = {Q_H} J\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Carnot efficiency: η = 1 - T_C/T_H = {eta_carnot:.4f} = {eta_carnot*100:.1f}%\")\n    print(f\"  Work output: W = η·Q_H = {W:.1f} J\")\n    print(f\"  Heat rejected: Q_C = Q_H - W = {Q_C:.1f} J\")\n    print(f\"  Verification: Q_C/T_C = Q_H/T_H? {Q_C/T_C:.4f} = {Q_H/T_H:.4f}\")\n    print()\n    return eta_carnot, W, Q_C\n\n\n# ============================================================================\n# Exercise 7: Otto Cycle Efficiency\n# ============================================================================\n\ndef exercise_7():\n    \"\"\"\n    An Otto cycle (gasoline engine):\n    - Compression ratio: r = V_1/V_2 = 8\n    - γ = 1.4 (air-fuel mixture)\n    \n    Calculate the thermal efficiency.\n    Efficiency: η = 1 - 1/r^(γ-1)\n    \"\"\"\n    r = 8  # Compression ratio\n    gamma = 1.4\n    \n    # Otto cycle efficiency\n    eta_otto = 1 - 1 / (r**(gamma - 1))\n    \n    # Compare with Carnot between same T_min and T_max\n    # T_max/T_min = r^(γ-1)\n    T_ratio = r**(gamma - 1)\n    eta_carnot_comparison = 1 - 1 / T_ratio\n    \n    print(\"Exercise 7: Otto Cycle (Gasoline Engine)\")\n    print(f\"  Compression ratio: r = {r}\")\n    print(f\"  Heat capacity ratio: γ = {gamma}\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Otto cycle efficiency: η = 1 - 1/r^(γ-1) = {eta_otto:.4f} = {eta_otto*100:.1f}%\")\n    print(f\"  Temperature ratio: T_max/T_min = r^(γ-1) = {T_ratio:.2f}\")\n    print(f\"  Carnot limit at same T ratio: η_c = {eta_carnot_comparison:.4f} = {eta_carnot_comparison*100:.1f}%\")\n    print(f\"  Otto is less than Carnot (expected for real cycle)\")\n    print()\n    return eta_otto\n\n\n# ============================================================================\n# Exercise 8: Refrigerator COP\n# ============================================================================\n\ndef exercise_8():\n    \"\"\"\n    A refrigerator:\n    - T_C = 250 K (inside)\n    - T_H = 300 K (outside)\n    - Heat removed from inside: Q_C = 2000 J\n    \n    Calculate COP and work required (for ideal Carnot refrigerator).\n    \"\"\"\n    T_C = 250  # K (cold side)\n    T_H = 300  # K (hot side)\n    Q_C = 2000  # J (heat removed from cold side)\n    \n    # For Carnot refrigerator: COP = T_C / (T_H - T_C)\n    COP = T_C / (T_H - T_C)\n    \n    # Work required: W = Q_C / COP\n    W_required = Q_C / COP\n    \n    # Heat delivered to hot side: Q_H = Q_C + W\n    Q_H = Q_C + W_required\n    \n    print(\"Exercise 8: Refrigerator Coefficient of Performance\")\n    print(f\"  Cold side (inside): T_C = {T_C} K\")\n    print(f\"  Hot side (outside): T_H = {T_H} K\")\n    print(f\"  Heat removed from inside: Q_C = {Q_C} J\")\n    print(f\"  \\nCalculated values (ideal Carnot):\")\n    print(f\"  COP = T_C/(T_H - T_C) = {COP:.2f}\")\n    print(f\"  Work required: W = Q_C/COP = {W_required:.1f} J\")\n    print(f\"  Heat delivered outside: Q_H = Q_C + W = {Q_H:.1f} J\")\n    print(f\"  (Higher COP = more efficient refrigerator)\")\n    print()\n    return COP, W_required\n\n\n# ============================================================================\n# Exercise 9: Entropy Change\n# ============================================================================\n\ndef exercise_9():\n    \"\"\"\n    Heat transfer in reversible isothermal process:\n    - n = 1 mole\n    - T = 300 K (constant)\n    - Volume expands from 0.01 m³ to 0.05 m³\n    \n    Calculate entropy change.\n    ΔS = Q_rev/T = nR ln(Vf/Vi)\n    \"\"\"\n    n = 1  # mole\n    T = 300  # K\n    V_i = 0.01  # m³\n    V_f = 0.05  # m³\n    \n    # Heat in isothermal process\n    Q = n * R * T * np.log(V_f / V_i)\n    \n    # Entropy change: ΔS = Q_rev/T\n    delta_S = Q / T\n    \n    # Alternative form: ΔS = nR ln(Vf/Vi)\n    delta_S_alt = n * R * np.log(V_f / V_i)\n    \n    print(\"Exercise 9: Entropy Change\")\n    print(f\"  Number of moles: n = {n} mol\")\n    print(f\"  Temperature: T = {T} K (constant)\")\n    print(f\"  Initial volume: V_i = {V_i} m³\")\n    print(f\"  Final volume: V_f = {V_f} m³\")\n    print(f\"  \\nCalculated values:\")\n    print(f\"  Heat absorbed: Q = {Q:.1f} J\")\n    print(f\"  Entropy change: ΔS = Q/T = {delta_S:.4f} J/K\")\n    print(f\"  Alternative: ΔS = nR·ln(Vf/Vi) = {delta_S_alt:.4f} J/K\")\n    print(f\"  Entropy increases (irreversible expansion becomes possible)\")\n    print()\n    return delta_S\n\n\n# ============================================================================\n# Exercise 10: Heat Pump COP\n# ============================================================================\n\ndef exercise_10():\n    \"\"\"\n    A heat pump for space heating:\n    - T_C = 280 K (outside air)\n    - T_H = 310 K (inside heated space)\n    - Q_H = 5000 J (heat delivered inside)\n    \n    Calculate COP for heating.\n    \"\"\"\n    T_C = 280  # K (cold source)\n    T_H = 310  # K (hot space)\n    Q_H = 5000  # J (heat delivered to hot side)\n    \n    # For Carnot heat pump: COP_heat = T_H / (T_H - T_C)\n    COP_heat = T_H / (T_H - T_C)\n    \n    # Work required\n    W_required = Q_H / COP_heat\n    \n    # Heat extracted from cold side\n    Q_C = Q_H - W_required\n    \n    print(\"Exercise 10: Heat Pump for Space Heating\")\n    print(f\"  Cold side (outside): T_C = {T_C} K\")\n    print(f\"  Hot side (inside): T_H = {T_H} K\")\n    print(f\"  Heat delivered to heat: Q_H = {Q_H} J\")\n    print(f\"  \\nCalculated values (ideal Carnot):\")\n    print(f\"  COP_heat = T_H/(T_H - T_C) = {COP_heat:.2f}\")\n    print(f\"  Work input required: W = {W_required:.1f} J\")\n    print(f\"  Heat extracted from outside: Q_C = {Q_C:.1f} J\")\n    print(f\"  Relationship: COP_heat = 1 + COP_refrigerator\")\n    print()\n    return COP_heat, W_required\n\n\n# ============================================================================\n# Main Execution\n# ============================================================================\n\nif __name__ == \"__main__\":\n    print(\"=\" * 80)\n    print(\"TOPIC 8: THERMODYNAMICS - PRACTICE EXERCISES\")\n    print(\"=\" * 80)\n    print()\n    \n    exercise_1()\n    exercise_2()\n    exercise_3()\n    exercise_4()\n    exercise_5()\n    exercise_6()\n    exercise_7()\n    exercise_8()\n    exercise_9()\n    exercise_10()\n    \n    print(\"=\" * 80)\n    print(\"All exercises completed!\")\n    print(\"=\" * 80)
